import{_ as o,o as r,c as t,ag as i}from"./chunks/framework.CHQlKclR.js";const p=JSON.parse('{"title":"Chassis Configuration & Utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/chassis.md","filePath":"api/chassis.md"}'),a={name:"api/chassis.md"};function d(l,e,s,n,c,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="chassis-configuration-utilities" tabindex="-1">Chassis Configuration &amp; Utilities <a class="header-anchor" href="#chassis-configuration-utilities" aria-label="Permalink to &quot;Chassis Configuration &amp; Utilities&quot;">​</a></h1><p>The <code>vortex::Drive</code> class is the central controller for your robot&#39;s drivetrain. It manages sensors, motor braking, driver curves, and power distribution.</p><h2 id="system-configuration" tabindex="-1">System Configuration <a class="header-anchor" href="#system-configuration" aria-label="Permalink to &quot;System Configuration&quot;">​</a></h2><p>These methods control the fundamental behavior of the drive motors and system reporting.</p><h3 id="drive-brake-set-pros-motor-brake-mode-e-t-brake-type" tabindex="-1"><code>drive_brake_set(pros::motor_brake_mode_e_t brake_type)</code> <a class="header-anchor" href="#drive-brake-set-pros-motor-brake-mode-e-t-brake-type" aria-label="Permalink to &quot;`drive_brake_set(pros::motor_brake_mode_e_t brake_type)`&quot;">​</a></h3><p>Changes how the motors behave when they are not under active control.</p><ul><li><code>pros::E_MOTOR_BRAKE_COAST</code>: No braking.</li><li><code>pros::E_MOTOR_BRAKE_BRAKE</code>: Electric braking.</li><li><code>pros::E_MOTOR_BRAKE_HOLD</code>: Active position holding.</li></ul><h3 id="drive-current-limit-set-int-ma-drive-current-limit-get" tabindex="-1"><code>drive_current_limit_set(int mA)</code> / <code>drive_current_limit_get()</code> <a class="header-anchor" href="#drive-current-limit-set-int-ma-drive-current-limit-get" aria-label="Permalink to &quot;`drive_current_limit_set(int mA)` / `drive_current_limit_get()`&quot;">​</a></h3><p>Sets or retrieves the maximum current (in milliamps) the drive motors can pull before internal clipping.</p><h3 id="pid-drive-toggle-bool-toggle-pid-print-toggle-bool-toggle" tabindex="-1"><code>pid_drive_toggle(bool toggle)</code> / <code>pid_print_toggle(bool toggle)</code> <a class="header-anchor" href="#pid-drive-toggle-bool-toggle-pid-print-toggle-bool-toggle" aria-label="Permalink to &quot;`pid_drive_toggle(bool toggle)` / `pid_print_toggle(bool toggle)`&quot;">​</a></h3><ul><li><code>pid_drive_toggle</code>: Enables or disables the internal PID loops for autonomous motions.</li><li><code>pid_print_toggle</code>: Enables or disables terminal logging during autonomous motions.</li></ul><hr><h2 id="driver-control-opcontrol" tabindex="-1">Driver Control (Opcontrol) <a class="header-anchor" href="#driver-control-opcontrol" aria-label="Permalink to &quot;Driver Control (Opcontrol)&quot;">​</a></h2><p>Vortex provides sophisticated joystick processing, including dual-motor grouping and customizable input curves.</p><h3 id="opcontrol-tank-opcontrol-arcade-standard-e-type-stick-type" tabindex="-1"><code>opcontrol_tank()</code> / <code>opcontrol_arcade_standard(e_type stick_type)</code> <a class="header-anchor" href="#opcontrol-tank-opcontrol-arcade-standard-e-type-stick-type" aria-label="Permalink to &quot;`opcontrol_tank()` / `opcontrol_arcade_standard(e_type stick_type)`&quot;">​</a></h3><p>Activates driver control in your <code>opcontrol()</code> loop.</p><ul><li><code>opcontrol_tank</code>: Left stick controls left side, right stick controls right side.</li><li><code>opcontrol_arcade_standard</code>: Standard arcade drive (Forward/Turn on same stick or split).</li></ul><h3 id="opcontrol-curve-default-set-double-left-double-right-0" tabindex="-1"><code>opcontrol_curve_default_set(double left, double right = 0)</code> <a class="header-anchor" href="#opcontrol-curve-default-set-double-left-double-right-0" aria-label="Permalink to &quot;`opcontrol_curve_default_set(double left, double right = 0)`&quot;">​</a></h3><p>Sets the joystick sensitivity curves. A value of <code>0</code> is linear, while higher values provide more precision at low speeds.</p><h3 id="opcontrol-drive-activebrake-set-double-kp-double-ki-double-kd" tabindex="-1"><code>opcontrol_drive_activebrake_set(double kp, double ki, double kd)</code> <a class="header-anchor" href="#opcontrol-drive-activebrake-set-double-kp-double-ki-double-kd" aria-label="Permalink to &quot;`opcontrol_drive_activebrake_set(double kp, double ki, double kd)`&quot;">​</a></h3><p>Enables an &quot;active brake&quot; mode where the robot uses a PID loop to stay perfectly still when joysticks are released.</p><hr><h2 id="imu-sensor-management" tabindex="-1">IMU &amp; Sensor Management <a class="header-anchor" href="#imu-sensor-management" aria-label="Permalink to &quot;IMU &amp; Sensor Management&quot;">​</a></h2><p>Utilities for calibrating and interacting with the V5 Inertial Sensor.</p><h3 id="drive-imu-calibrate-bool-run-loading-animation-true" tabindex="-1"><code>drive_imu_calibrate(bool run_loading_animation = true)</code> <a class="header-anchor" href="#drive-imu-calibrate-bool-run-loading-animation-true" aria-label="Permalink to &quot;`drive_imu_calibrate(bool run_loading_animation = true)`&quot;">​</a></h3><p>Starts the IMU calibration process. Returns <code>true</code> if successful.</p><h3 id="drive-imu-reset-double-heading-0" tabindex="-1"><code>drive_imu_reset(double heading = 0)</code> <a class="header-anchor" href="#drive-imu-reset-double-heading-0" aria-label="Permalink to &quot;`drive_imu_reset(double heading = 0)`&quot;">​</a></h3><p>Resets the IMU rotation value to the specified heading (default is 0).</p><h3 id="drive-imu-scaler-set-double-scaler-drive-imu-scaler-get" tabindex="-1"><code>drive_imu_scaler_set(double scaler)</code> / <code>drive_imu_scaler_get()</code> <a class="header-anchor" href="#drive-imu-scaler-set-double-scaler-drive-imu-scaler-get" aria-label="Permalink to &quot;`drive_imu_scaler_set(double scaler)` / `drive_imu_scaler_get()`&quot;">​</a></h3><p>Adjusts for gyro drift or non-perfect 360-degree rotations.</p><hr><h2 id="pto-power-take-off" tabindex="-1">PTO (Power Take-Off) <a class="header-anchor" href="#pto-power-take-off" aria-label="Permalink to &quot;PTO (Power Take-Off)&quot;">​</a></h2><p>Dynamically remove motors from the drivetrain to power other mechanisms.</p><h3 id="pto-add-std-vector-pros-motor-motors" tabindex="-1"><code>pto_add(std::vector&lt;pros::Motor&gt; motors)</code> <a class="header-anchor" href="#pto-add-std-vector-pros-motor-motors" aria-label="Permalink to &quot;`pto_add(std::vector&lt;pros::Motor&gt; motors)`&quot;">​</a></h3><p>Removes the specified motors from the drivetrain control list.</p><h3 id="pto-remove-std-vector-pros-motor-motors" tabindex="-1"><code>pto_remove(std::vector&lt;pros::Motor&gt; motors)</code> <a class="header-anchor" href="#pto-remove-std-vector-pros-motor-motors" aria-label="Permalink to &quot;`pto_remove(std::vector&lt;pros::Motor&gt; motors)`&quot;">​</a></h3><p>Returns the specified motors to the drivetrain control list.</p><hr><h2 id="telemetry" tabindex="-1">Telemetry <a class="header-anchor" href="#telemetry" aria-label="Permalink to &quot;Telemetry&quot;">​</a></h2><p>Real-time data access for diagnostics and custom logging.</p><h3 id="drive-sensor-left-drive-sensor-right" tabindex="-1"><code>drive_sensor_left()</code> / <code>drive_sensor_right()</code> <a class="header-anchor" href="#drive-sensor-left-drive-sensor-right" aria-label="Permalink to &quot;`drive_sensor_left()` / `drive_sensor_right()`&quot;">​</a></h3><p>Returns the current distance traveled by each side in inches.</p><h3 id="drive-velocity-left-drive-velocity-right" tabindex="-1"><code>drive_velocity_left()</code> / <code>drive_velocity_right()</code> <a class="header-anchor" href="#drive-velocity-left-drive-velocity-right" aria-label="Permalink to &quot;`drive_velocity_left()` / `drive_velocity_right()`&quot;">​</a></h3><p>Returns the current motor velocity in RPM.</p><h3 id="drive-ma-left-drive-ma-right" tabindex="-1"><code>drive_mA_left()</code> / <code>drive_mA_right()</code> <a class="header-anchor" href="#drive-ma-left-drive-ma-right" aria-label="Permalink to &quot;`drive_mA_left()` / `drive_mA_right()`&quot;">​</a></h3><p>Returns the current power draw of the drive side in milliamps.</p><h3 id="drive-current-left-over-drive-current-right-over" tabindex="-1"><code>drive_current_left_over()</code> / <code>drive_current_right_over()</code> <a class="header-anchor" href="#drive-current-left-over-drive-current-right-over" aria-label="Permalink to &quot;`drive_current_left_over()` / `drive_current_right_over()`&quot;">​</a></h3><p>Returns <code>true</code> if the motor group is currently exceeding its safety current limit.</p>',48)])])}const _=o(a,[["render",d]]);export{p as __pageData,_ as default};
